import { useState } from "react";
import { Popper, Button, Box } from "@sistent/sistent";

export const PopperBasicDemo = () => {
  const [anchorEl, setAnchorEl] = useState(null);
  const [open, setOpen] = useState(false);
  const handleClick = (event) => {
    setAnchorEl(event.currentTarget);
    setOpen((prev) => !prev);
  };
  return (
    <>
      <Popper open={open} anchorEl={anchorEl} placement="bottom">
        <Box sx={{ border: 1, p: 1, bgcolor: "background.paper" }}>
          The content of the Popper.
        </Box>
      </Popper>
      <Row $Hcenter className="image-container">
        <Button
          variant="contained"
          label="Toggle Popper"
          size="medium"
          onClick={handleClick}
        />
      </Row>
    </>
  );
};

export const PopperPlacementDemo = () => {
  const [anchorEl, setAnchorEl] = useState(null);
  const [open, setOpen] = useState(false);
  const handleClick = (event) => {
    setAnchorEl(event.currentTarget);
    setOpen((prev) => !prev);
  };
  return (
    <>
      <Popper open={open} anchorEl={anchorEl} placement="right">
        <Box sx={{ border: 1, p: 1, bgcolor: "background.paper" }}>
          The content of the Popper.
        </Box>
      </Popper>
      <Row $Hcenter className="image-container">
        <Button
          variant="contained"
          label="Toggle Popper"
          size="medium"
          onClick={handleClick}
        />
      </Row>
    </>
  );
};

Poppers are critical for displaying information dynamically and can be used in various scenarios like tooltips, dropdowns, and menus. By anchoring the content to a reference element, Poppers provide users with relevant information as they interact with the interface.

<a id="Usage"><h2>Usage</h2></a>
<p>The Popper component should be used in cases where context-sensitive information is necessary. Here are common use cases:</p>
<ul>
  <li>Tooltips that provide additional information on hover.</li>
  <li>Dropdown menus for navigation or selections.</li>
  <li>Modals for confirmations or additional content.</li>
</ul>

<a id="Basic Example"><h3>Basic Example</h3></a>
<p>Below is a simple example of how to use the Popper component to display content relative to a button.</p>

<ThemeWrapper>
  <PopperBasicDemo />
</ThemeWrapper>

<p>The `anchorEl` prop specifies the element to which the Popper will be anchored. The `open` prop controls its visibility.</p>

<a id="Styling and Positioning"><h3>Styling and Positioning</h3></a>
<p>You can customize the positioning of the Popper using the `placement` prop to define where the Popper appears relative to the anchor element.</p>

